const u=window.API_CONFIG?.BASE_URL||"http://localhost:3001/api";async function e(t,r){const o=new AbortController,s=setTimeout(()=>o.abort(),3e4);try{const n={"Content-Type":"application/json"},l=localStorage.getItem("auth_token")||window.Auth?.token;l&&(n.Authorization=`Bearer ${l}`);const a=await fetch(`${u}${t}`,{method:"POST",credentials:"include",headers:n,body:JSON.stringify(r),signal:o.signal});if(!a.ok){const y=await a.text();let c;try{c=JSON.parse(y).error}catch{c=y}throw new Error(c||`Chyba serveru (${a.status})`)}const i=await a.json();if(!i.success)throw new Error(i.error||"Nezn\xE1m\xE1 chyba");return i.response}catch(n){throw n.name==="AbortError"?new Error("Po\u017Eadavek vypr\u0161el. Zkuste to pros\xEDm znovu."):(console.error(`API Error (${t}):`,n),n)}finally{clearTimeout(s)}}export async function askCrystalBall(t,r=[]){return e("/crystal-ball",{question:t,history:r})}export async function readTarot(t,r,o="t\u0159\xEDkartov\xFD"){return e("/tarot",{question:t,cards:r,spreadType:o})}export async function analyzeNatalChart({birthDate:t,birthTime:r,birthPlace:o,name:s}){return e("/natal-chart",{birthDate:t,birthTime:r,birthPlace:o,name:s})}export async function analyzeSynastry(t,r){return e("/synastry",{person1:t,person2:r})}export async function getDailyHoroscope(t,r){return e("/horoscope",{sign:t,date:r})}export async function generateMeditation({emotion:t,intention:r,sign:o}){return e("/meditation",{emotion:t,intention:r,sign:o})}typeof window<"u"&&(window.GeminiService={askCrystalBall,readTarot,analyzeNatalChart,analyzeSynastry,getDailyHoroscope,generateMeditation,getDailyWisdom:(t,r,o)=>e("/daily-wisdom",{sign:t,moonPhase:r,lang:o})});export async function getDailyWisdom(t,r,o){return e("/daily-wisdom",{sign:t,moonPhase:r,lang:o})}
